package com.company.snackledger.kiosk.ui;import com.company.snackledger.kiosk.api.Dto.ItemDto;import java.math.BigDecimal;import java.util.*;public class Cart{private final Map<Long,Line> lines=new LinkedHashMap<>();private String requestId=UUID.randomUUID().toString();public void add(ItemDto i){lines.compute(i.id(),(id,l)->l==null?new Line(i,1):l.inc());}public void increase(Long id){lines.computeIfPresent(id,(k,l)->l.inc());}public void decrease(Long id){lines.computeIfPresent(id,(k,l)->l.quantity>1?new Line(l.item,l.quantity-1):null);}public void remove(Long id){lines.remove(id);}public void clearForNewPurchase(){lines.clear();requestId=UUID.randomUUID().toString();}public String requestId(){return requestId;}public BigDecimal total(){return lines.values().stream().map(l->l.item.price().multiply(BigDecimal.valueOf(l.quantity))).reduce(BigDecimal.ZERO,BigDecimal::add);}public Collection<Line> lines(){return lines.values();}public record Line(ItemDto item,int quantity){Line inc(){return new Line(item,quantity+1);}}}
